def group_by_level(arr):
    """
    Groups elements of an array into sub-arrays based on their level in a binary tree structure.

    Args:
        arr: The input array.

    Returns:
        A list of lists, where each inner list represents a level in the binary tree.
    """

    if not arr:
        return []

    result = []
    queue = [arr]

    while queue:
        level_nodes = queue.pop(0)
        result.append(level_nodes)

        next_level = []
        for i in range(0, len(level_nodes), 2):
            if i + 1 < len(level_nodes):
                next_level.append([level_nodes[i], level_nodes[i+1]])
            else:
                next_level.append([level_nodes[i]])

        queue.extend(next_level)

    return result

